service-task-definition.script:
// OAuth2 config sample at [OAuth 2.0 Setting]
// - Authorization Endpoint URL: https://login.microsoftonline.com/organizations/oauth2/v2.0/authorize
// - Token Endpoint URL: https://login.microsoftonline.com/organizations/oauth2/v2.0/token
// - Scope: ChannnelMessage.Send offline_access
// - Consumer Key: (Get by Microsoft Azure Active Directory)
// - Consumer Secret: (Get by Microsoft Azure Active Directory)

const GRAPH_URI = 'https://graph.microsoft.com/v1.0/';

const main = () => {
    //// == 工程コンフィグの参照 / Config Retrieving ==
    const oauth2 = configs.getObject('conf_OAuth2');
    const targetUrl = retrieveTargetUrl();
    const subject = configs.get('conf_Subject');
    const markdownText = configs.get('conf_Markdown') ?? '';
    if (markdownText === '') {
        throw new Error('Post Content is empty.');
    }
    const fileUrls = retrieveFileUrls();

    //// == 演算 / Calculating ==
    const {teamId, channelId, messageId} = parseTargetUrl(targetUrl);
    const postUrl = post(oauth2, teamId, channelId, messageId, subject, markdownText, fileUrls);

    //// == ワークフローデータへの代入 / Data Updating ==
    saveData('conf_PostUrl', postUrl);
};

/**
 * config から投稿先 URL を読み出す
 * 空の場合はエラー
 * @returns {String}
 */
const retrieveTargetUrl = () => {
    let targetUrl = configs.get('conf_TargetUrl');
    const def = configs.getObject('conf_TargetUrl');
    if (def !== null) {
        targetUrl = engine.findData(def);
    }
    if (targetUrl === null || targetUrl === '') {
        throw new Error('Target URL is empty.');
    }
    return targetUrl;
};

/**
 * config から添付ファイルの URL 一覧を読み出す
 * 未設定の場合、空配列を返す
 * @returns {Array<String>}
 */
const retrieveFileUrls = () => {
    const def = configs.getObject('conf_FileUrls');
    if (def === null) {
        return [];
    }
    const str = engine.findData(def);
    if (str === null || str === '') {
        return [];
    }
    return str.split('\n').filter(url => url !== '');
};

/**
 * 投稿先の URL をパースし、teamId, channelId, messageId を返す
 * チャネル URL: https://{domain}/{path}/channel/{channelId}/{channelName}?groupId={teamId}&tenantId={tenantId}
 * チャネルメッセージ URL: https://{domain}/{path}/message/{channelId}/{messageId}?...&groupId={teamId}&...
 * @param {String} targetUrl
 * @returns {Object} teamId, channelId, messageId
 */
const parseTargetUrl = (targetUrl) => {
    const [pathPart, queryPart] = targetUrl.split('?');
    const pathSegments = pathPart.split('/');
    const queryParams = parseQueryParams(queryPart);

    // メッセージ URL の判定
    const messageIndex = pathSegments.indexOf('message');
    if (messageIndex !== -1 && messageIndex + 2 < pathSegments.length) {
        const channelId = decodeURIComponent(pathSegments[messageIndex + 1]);
        const messageId = decodeURIComponent(pathSegments[messageIndex + 2]);
        const teamId = queryParams.groupId;
        if (teamId === undefined) {
            throw new Error(`groupId not found in target URL: ${targetUrl}`);
        }
        engine.log(`teamId: ${teamId}, channelId: ${channelId}, messageId: ${messageId}`);
        return { teamId, channelId, messageId };
    }

    // チャネル URL の判定
    const channelIndex = pathSegments.indexOf('channel');
    if (channelIndex === -1 || channelIndex + 1 >= pathSegments.length) {
        throw new Error(`Invalid Target URL: ${targetUrl}`);
    }
    const channelId = decodeURIComponent(pathSegments[channelIndex + 1]);
    const teamId = queryParams.groupId;
    if (teamId === undefined) {
        throw new Error(`groupId not found in target URL: ${targetUrl}`);
    }
    engine.log(`teamId: ${teamId}, channelId: ${channelId}`);
    return { teamId, channelId, messageId: null };
};

/**
 * クエリ文字列をパースしてオブジェクトにする
 * @param {String|undefined} queryPart
 * @returns {Object}
 */
const parseQueryParams = (queryPart) => {
    if (queryPart === undefined) {
        return {};
    }
    const params = {};
    queryPart.split('&').forEach(param => {
        const [key, ...rest] = param.split('=');
        params[key] = rest.join('='); // value に = が含まれる場合を考慮
    });
    return params;
};

/**
 * メッセージを投稿する
 * @param {AuthSettingWrapper} oauth2  OAuth2 設定情報
 * @param {String} teamId
 * @param {String} channelId
 * @param {String|null} messageId
 * @param {Strung} subject
 * @param {String} markdownText
 * @param {Array<String>} fileUrls
 * @returns {String} 投稿したメッセージの URL
 */
const post = (oauth2, teamId, channelId, messageId, subject, markdownText, fileUrls) => {
    let url;
    if (messageId !== null) { // チャネルメッセージへの返信
        url = `${GRAPH_URI}teams/${encodeURIComponent(teamId)}/channels/${encodeURIComponent(channelId)}/messages/${encodeURIComponent(messageId)}/replies`;
    } else { // チャネルへの投稿
        url = `${GRAPH_URI}teams/${encodeURIComponent(teamId)}/channels/${encodeURIComponent(channelId)}/messages`;
    }
    const reqBody = {
        body: {
            contentType: 'html',
            content: markdown.toHtml(markdownText)
        }
    };
    if (subject !== '' && messageId === null) {
        reqBody.subject = subject;
    }
    if (fileUrls.length > 0) {
        reqBody.attachments = fileUrls.map(fileUrl => ({
            contentType: 'reference',
            contentUrl: fileUrl
        }));
    }
    const response = httpClient.begin()
        .authSetting(oauth2)
        .body(JSON.stringify(reqBody), 'application/json; charset=UTF-8')
        .post(url);
    const status = response.getStatusCode();
    const responseStr = response.getResponseAsString();
    if (status !== 201) {
        engine.log(responseStr);
        throw new Error(`Failed to post message. status: ${status}`);
    }
    return JSON.parse(responseStr).webUrl;
};

/**
 * データ項目への保存
 * @param {String} configName
 * @param {*} data
 */
const saveData = (configName, data) => {
    const def = configs.getObject(configName);
    if (def === null) {
        return;
    }
    engine.setData(def, data);
};

service-task-definition.test:
const SAMPLE_TEAM_ID = 'aaaaaaaa-bbbb-cccc-dddd-eeeeeeeeeeee';
const SAMPLE_CHANNEL_ID = '19:channelId123@thread.tacv2';
const SAMPLE_MESSAGE_ID = '1681234567890';
const SAMPLE_CHANNEL_URL = `https://teams.microsoft.com/l/channel/${encodeURIComponent(SAMPLE_CHANNEL_ID)}/General?groupId=${SAMPLE_TEAM_ID}&tenantId=11111111-2222-3333-4444-555555555555`;
const SAMPLE_MESSAGE_URL = `https://teams.microsoft.com/l/message/${encodeURIComponent(SAMPLE_CHANNEL_ID)}/${SAMPLE_MESSAGE_ID}?tenantId=11111111-2222-3333-4444-555555555555&groupId=${SAMPLE_TEAM_ID}&parentMessageId=${SAMPLE_MESSAGE_ID}`;

/**
 * 設定の準備 - 投稿先 URL は直接入力
 * @param {String} targetUrl
 * @param {String} subject
 * @param {String} markdownText
 * @param {Boolean} savePostUrl
 * @returns {DataDefinitionView|null} postUrlDef
 */
const prepareConfigs = (targetUrl, subject, markdownText, savePostUrl) => {
    const oauth2 = httpClient.createAuthSettingOAuth2(
        'Microsoft Teams',
        'https://login.microsoftonline.com/organizations/oauth2/v2.0/authorize',
        'https://login.microsoftonline.com/organizations/oauth2/v2.0/token',
        'https://graph.microsoft.com/ChannelMessage.Send offline_access',
        'client_id',
        'client_secret',
        'access_token'
    );
    configs.putObject('conf_OAuth2', oauth2);
    configs.put('conf_TargetUrl', targetUrl);
    configs.put('conf_Subject', subject);
    configs.put('conf_Markdown', markdownText);

    if (savePostUrl) {
        const postUrlDef = engine.createDataDefinition('投稿 URL', 1, 'q_postUrl', 'STRING_TEXTFIELD');
        configs.putObject('conf_PostUrl', postUrlDef);
        return postUrlDef;
    }
    return null;
};

/**
 * 異常系のテスト
 * @param {String} errorMsg
 */
const assertError = (errorMsg) => {
    let failed = false;
    try {
        main();
    } catch (e) {
        failed = true;
        expect(e.message).toEqual(errorMsg);
    }
    if (!failed) {
        fail('No error was thrown.');
    }
};

/**
 * conf_FileUrls にデータ項目を設定する
 * @param {String|null} fileUrlsStr 改行区切りの URL 文字列（null で値未設定）
 */
const setFileUrls = (fileUrlsStr) => {
    const def = engine.createDataDefinition('ファイル URL', 3, 'q_fileUrls', 'STRING_TEXTAREA');
    if (fileUrlsStr !== null) {
        engine.setData(def, fileUrlsStr);
    }
    configs.putObject('conf_FileUrls', def);
};

/**
 * POST リクエストの検証
 * @param {Object} request
 * @param {String} teamId
 * @param {String} channelId
 * @param {String|null} messageId
 * @param {String} subject
 * @param {String} markdownText
 * @param {Array<String>} fileUrls
 */
const assertPostRequest = ({url, method, contentType, headers, body}, teamId, channelId, messageId, subject, markdownText, fileUrls = []) => {
    let expectedUrl;
    if (messageId !== null) {
        expectedUrl = `${GRAPH_URI}teams/${encodeURIComponent(teamId)}/channels/${encodeURIComponent(channelId)}/messages/${encodeURIComponent(messageId)}/replies`;
    } else {
        expectedUrl = `${GRAPH_URI}teams/${encodeURIComponent(teamId)}/channels/${encodeURIComponent(channelId)}/messages`;
    }
    expect(url).toEqual(expectedUrl);
    expect(method).toEqual('POST');
    expect(contentType).toEqual('application/json; charset=UTF-8');
    expect(headers.Authorization).toEqual('Bearer access_token');
    const bodyObj = JSON.parse(body);
    expect(bodyObj.body.contentType).toEqual('html');
    expect(bodyObj.body.content).toEqual(markdown.toHtml(markdownText));
    if (subject !== '' && messageId === null) {
        expect(bodyObj.subject).toEqual(subject);
    } else {
        expect(bodyObj.subject).toEqual(undefined);
    }
    if (fileUrls.length > 0) {
        expect(bodyObj.attachments).toEqual(fileUrls.map(fileUrl => ({
            contentType: 'reference',
            contentUrl: fileUrl
        })));
    } else {
        expect(bodyObj.attachments).toEqual(undefined);
    }
};

/**
 * 投稿先 URL が空（データ項目の値が空）
 */
test('Error - Target URL is empty (data item with null value)', () => {
    prepareConfigs('', '', '**Hello**', false);
    // conf_TargetUrl をデータ項目に差し替え（値未設定 → null）
    const targetUrlDef = engine.createDataDefinition('投稿先 URL', 2, 'q_targetUrl', 'STRING_TEXTFIELD');
    configs.putObject('conf_TargetUrl', targetUrlDef);

    assertError('Target URL is empty.');
});

/**
 * 投稿文が空
 */
test('Error - Post Content is empty', () => {
    prepareConfigs(SAMPLE_CHANNEL_URL, '', '', false);
    assertError('Post Content is empty.');
});

/**
 * URL に channel も message もない
 */
test('Error - Invalid Target URL', () => {
    const url = 'https://teams.microsoft.com/l/something/else';
    prepareConfigs(url, '', '**Hello**', false);
    assertError(`Invalid Target URL: ${url}`);
});

/**
 * チャネル URL に groupId がない
 */
test('Error - Channel URL without groupId', () => {
    const url = `https://teams.microsoft.com/l/channel/${encodeURIComponent(SAMPLE_CHANNEL_ID)}/General?tenantId=11111111-2222-3333-4444-555555555555`;
    prepareConfigs(url, '', '**Hello**', false);
    assertError(`groupId not found in target URL: ${url}`);
});

/**
 * メッセージ URL に groupId がない
 */
test('Error - Message URL without groupId', () => {
    const url = `https://teams.microsoft.com/l/message/${encodeURIComponent(SAMPLE_CHANNEL_ID)}/${SAMPLE_MESSAGE_ID}?tenantId=11111111-2222-3333-4444-555555555555`;
    prepareConfigs(url, '', '**Hello**', false);
    assertError(`groupId not found in target URL: ${url}`);
});

/**
 * POST リクエストでエラー
 */
test('Error - POST request fails', () => {
    prepareConfigs(SAMPLE_CHANNEL_URL, '', '**Hello**', false);
    httpClient.setRequestHandler((request) => {
        assertPostRequest(request, SAMPLE_TEAM_ID, SAMPLE_CHANNEL_ID, null, '', '**Hello**');
        return httpClient.createHttpResponse(400, 'application/json', '{}');
    });
    assertError('Failed to post message. status: 400');
});

/**
 * 成功 - チャネルに投稿、件名なし、投稿 URL 保存なし
 */
test('Success - Channel post, no subject, postUrl not saved', () => {
    prepareConfigs(SAMPLE_CHANNEL_URL, '', '**Hello**', false);
    const webUrl = 'https://teams.microsoft.com/l/message/channelId/1234567890';
    httpClient.setRequestHandler((request) => {
        assertPostRequest(request, SAMPLE_TEAM_ID, SAMPLE_CHANNEL_ID, null, '', '**Hello**');
        return httpClient.createHttpResponse(201, 'application/json', JSON.stringify({id: '1234567890', webUrl}));
    });
    main();
});

/**
 * 成功 - チャネルに投稿、件名あり、投稿 URL 保存あり
 */
test('Success - Channel post, with subject, postUrl saved', () => {
    const postUrlDef = prepareConfigs(SAMPLE_CHANNEL_URL, 'Test Subject', '**Hello**', true);
    const webUrl = 'https://teams.microsoft.com/l/message/channelId/1234567890';
    httpClient.setRequestHandler((request) => {
        assertPostRequest(request, SAMPLE_TEAM_ID, SAMPLE_CHANNEL_ID, null, 'Test Subject', '**Hello**');
        return httpClient.createHttpResponse(201, 'application/json', JSON.stringify({id: '1234567890', webUrl}));
    });
    main();
    expect(engine.findData(postUrlDef)).toEqual(webUrl);
});

/**
 * 成功 - 投稿先 URL をデータ項目から取得
 */
test('Success - Target URL from data item', () => {
    prepareConfigs('', '', '**Hello**', false);
    // conf_TargetUrl をデータ項目に差し替え
    const targetUrlDef = engine.createDataDefinition('投稿先 URL', 2, 'q_targetUrl', 'STRING_TEXTFIELD');
    engine.setData(targetUrlDef, SAMPLE_CHANNEL_URL);
    configs.putObject('conf_TargetUrl', targetUrlDef);

    const webUrl = 'https://teams.microsoft.com/l/message/channelId/1234567890';
    httpClient.setRequestHandler((request) => {
        assertPostRequest(request, SAMPLE_TEAM_ID, SAMPLE_CHANNEL_ID, null, '', '**Hello**');
        return httpClient.createHttpResponse(201, 'application/json', JSON.stringify({id: '1234567890', webUrl}));
    });
    main();
});

/**
 * 成功 - メッセージへの返信、件名なし
 */
test('Success - Reply, no subject', () => {
    prepareConfigs(SAMPLE_MESSAGE_URL, '', '**Reply**', false);
    const webUrl = 'https://teams.microsoft.com/l/message/channelId/9876543210';
    httpClient.setRequestHandler((request) => {
        assertPostRequest(request, SAMPLE_TEAM_ID, SAMPLE_CHANNEL_ID, SAMPLE_MESSAGE_ID, '', '**Reply**');
        return httpClient.createHttpResponse(201, 'application/json', JSON.stringify({id: '9876543210', webUrl}));
    });
    main();
});

/**
 * 成功 - メッセージへの返信、件名あり（件名は無視される）
 */
test('Success - Reply with subject (subject ignored)', () => {
    const postUrlDef = prepareConfigs(SAMPLE_MESSAGE_URL, 'Ignored Subject', '**Reply**', true);
    const webUrl = 'https://teams.microsoft.com/l/message/channelId/9876543210';
    httpClient.setRequestHandler((request) => {
        assertPostRequest(request, SAMPLE_TEAM_ID, SAMPLE_CHANNEL_ID, SAMPLE_MESSAGE_ID, 'Ignored Subject', '**Reply**');
        return httpClient.createHttpResponse(201, 'application/json', JSON.stringify({id: '9876543210', webUrl}));
    });
    main();
    expect(engine.findData(postUrlDef)).toEqual(webUrl);
});

/**
 * 成功 - ファイル URL 付きで投稿
 */
test('Success - Channel post with file URLs', () => {
    prepareConfigs(SAMPLE_CHANNEL_URL, '', '**Hello**', false);
    const fileUrl1 = 'https://example.sharepoint.com/sites/team/Shared%20Documents/file1.txt';
    const fileUrl2 = 'https://example.sharepoint.com/sites/team/Shared%20Documents/file2.pdf';
    setFileUrls(`${fileUrl1}\n${fileUrl2}`);

    const webUrl = 'https://teams.microsoft.com/l/message/channelId/1234567890';
    httpClient.setRequestHandler((request) => {
        assertPostRequest(request, SAMPLE_TEAM_ID, SAMPLE_CHANNEL_ID, null, '', '**Hello**', [fileUrl1, fileUrl2]);
        return httpClient.createHttpResponse(201, 'application/json', JSON.stringify({id: '1234567890', webUrl}));
    });
    main();
});

/**
 * 成功 - ファイル URL に空行が含まれる場合、空行は無視される
 */
test('Success - File URLs with empty lines filtered', () => {
    prepareConfigs(SAMPLE_CHANNEL_URL, '', '**Hello**', false);
    const fileUrl = 'https://example.sharepoint.com/sites/team/Shared%20Documents/file1.txt';
    setFileUrls(`\n${fileUrl}\n\n`);

    const webUrl = 'https://teams.microsoft.com/l/message/channelId/1234567890';
    httpClient.setRequestHandler((request) => {
        assertPostRequest(request, SAMPLE_TEAM_ID, SAMPLE_CHANNEL_ID, null, '', '**Hello**', [fileUrl]);
        return httpClient.createHttpResponse(201, 'application/json', JSON.stringify({id: '1234567890', webUrl}));
    });
    main();
});
